# Declare names of shortcuts to be detected here. Names must match the detection script.
$Shortcuts = @(
    # This example contains its own icon as a base64 encoded variable. It will be decoded later and written as a .ico file.
    [PSCustomObject]@{
        Name          = "IT Email"
        Target        = "https://outlook.office.com"
        Arguments     = "" # URLs don't usually need arguments
        Base64Content = ""
        LocalIconPath = "" # Leave empty if using Base64Content
        IconIndex     = 0
    },
    [PSCustomObject]@{
        Name          = "IT Helpdesk"
        Target        = "https://live.hornbill.com/example/internal/home/"
        Arguments     = "" # URLs don't usually need arguments
        Base64Content = ""
        LocalIconPath = "" # Leave empty if using Base64Content
        IconIndex     = 0
    },
    # This example takes the icon from the .exe file so doesn't need an extra icon.
    [PSCustomObject]@{
        Name          = "Change BitLocker PIN"
        Target        = "$env:SystemRoot\System32\bdechangepin.exe"
        Arguments     = "" # Add flags here if needed, e.g., "-managed"
        Base64Content = "" # No encoded icon needed for local system apps
        LocalIconPath = "$env:SystemRoot\System32\bdechangepin.exe"
        IconIndex     = 0
    }
)

# Don't change anything below here
# Where the shortcuts are stored
$IntuneProgramDir = "$env:APPDATA\IntuneShortcuts"
# Create the dir if needed
if (-not (Test-Path $IntuneProgramDir)) { New-Item -ItemType Directory $IntuneProgramDir -Force | Out-Null }

# Setup WScript.Shell to create icons
$WScriptShell = New-Object -ComObject WScript.Shell

# Process each icon one at a time
foreach ($Item in $Shortcuts) {
    $Name = $Item.Name
    $FinalIconPath = ""

# 1. Handle Icon Logic (Base64 Decode vs Local Path)
    # If is base64 encoded...
    if (-not [string]::IsNullOrWhiteSpace($Item.Base64Content)) {
        # Setup icon file path and name based on declared shortcut name
        $CleanIco = Join-Path $IntuneProgramDir "$($Name).ico"
        
        try {
            $NeedsUpdate = $true
            
            # Check if file exists and if the content actually needs changing
            if (Test-Path $CleanIco) {
                $ExistingBytes = [System.IO.File]::ReadAllBytes($CleanIco)
                $NewBytes      = [System.Convert]::FromBase64String($Item.Base64Content)
                
                # Compare byte arrays to see if they are identical
                if ([System.Linq.Enumerable]::SequenceEqual($ExistingBytes, $NewBytes)) {
                    $NeedsUpdate = $false
                }
            } else {
                $NewBytes = [System.Convert]::FromBase64String($Item.Base64Content)
            }

            if ($NeedsUpdate) {
                # Force Garbage Collection to release any ghost handles before overwriting
                [System.GC]::Collect()
                [System.GC]::WaitForPendingFinalizers()
                
                [System.IO.File]::WriteAllBytes($CleanIco, $NewBytes)
                Write-Output "Updated icon file for: $Name"
            }
            
            # Icon used is the one generated from base64 decode
            $FinalIconPath = $CleanIco
        } catch {
            Write-Warning "Failed to process icon for $Name : $($_.Exception.Message)"
        }
    # else if is .exe or other containing own icon so can use that instead...
    } elseif (-not [string]::IsNullOrWhiteSpace($Item.LocalIconPath)) {
        # Icon used is the one contained in the target .exe etc.
        $FinalIconPath = $Item.LocalIconPath
    }

    # 2. Create Shortcut
    # Check $FinalIconPath is valid
    if (-not [string]::IsNullOrWhiteSpace($FinalIconPath) -and (Test-Path $FinalIconPath)) {
        # Get absolute path. Variables were failing in some instances.
        $AbsPath = (Get-Item $FinalIconPath).FullName
        # Shortcuts on desktop and start menu. How to get the user's desktop dir. Difficult when mapped to onedrive.
        $TargetDirs = @([Environment]::GetFolderPath("Desktop"), "$env:APPDATA\Microsoft\Windows\Start Menu\Programs")
        
        # Loop through target dirs
        foreach ($Dir in $TargetDirs) {
            # Create complete lnk/shortcut path
            $LnkPath = Join-Path $Dir "$Name.lnk"
            # Cleanup existing shortcut
            if (Test-Path $LnkPath) { Remove-Item $LnkPath -Force }

            # Create and save new shortcut
            $Shortcut = $WScriptShell.CreateShortcut($LnkPath)
            $Shortcut.TargetPath = $Item.Target
            if ($Item.Arguments) { $Shortcut.Arguments = $Item.Arguments }
            $Shortcut.IconLocation = "$AbsPath,$($Item.IconIndex)"
            $Shortcut.Save()
        }
    }
}

Write-Output "Remediation complete. All shortcuts and embedded icons deployed."